import HomeBanner from "../../Components/Header/HomeBanner";
import banner1 from "../../assets/images/banner1.png";
import Button from "@mui/material/Button";
import { IoIosArrowRoundForward } from "react-icons/io";
import React from "react";
import { Swiper, SwiperSlide } from "swiper/react";
import "swiper/css";
import "swiper/css/navigation";
import { Navigation } from "swiper/modules";
import ProducItem from "../../Components/Productitem";
import banner2 from "../../assets/images/banner2.png";
import HomeCat from "../../Components/HomeCat";
import banner3 from "../../assets/images/bnnn1.png";
import banner4 from "../../assets/images/bnnn2.png";
import banner5 from "../../assets/images/bnn6.png";
const Home = () => {
  return (
    <>
      <HomeBanner />
      <HomeCat />
      <section className="homeProducts">
        <div className="container">
          <div className="row">
            <div className="col-md-3"></div>
            <div className="col-md-9 productRow">
              <div class="d-flex align-items-center">
                {" "}
                <div class="info w-75">
                  {" "}
                  <h3 class="mb-0 hd">SẢN PHẨM BÁN CHẠY</h3>{" "}
                  <p class="text-light text-sml mb-0">
                    {" "}
                    Đừng bỏ lỡ các ưu đãi hiện tại cho đến cuối tháng 11{" "}
                  </p>{" "}
                </div>{" "}
                <Button className="viewAllButton ml-auto ">
                  {" "}
                  Xem tất cả <IoIosArrowRoundForward />{" "}
                </Button>
              </div>

              <div className="product_row w-100 mt-4">
                <Swiper
                  slidesPerView={4}
                  spaceBetween={0}
                  slidesPerGroup={1}
                  navigation={true}
                  modules={[Navigation]}
                  className="mySwiper"
                >
                  <SwiperSlide>
                    <ProducItem />
                  </SwiperSlide>
                  <SwiperSlide>
                    <ProducItem />
                  </SwiperSlide>
                  <SwiperSlide>
                    <ProducItem />
                  </SwiperSlide>
                  <SwiperSlide>
                    <ProducItem />
                  </SwiperSlide>
                  <SwiperSlide>
                    <ProducItem />
                  </SwiperSlide>
                  <SwiperSlide>
                    <ProducItem />
                  </SwiperSlide>
                  <SwiperSlide>
                    <ProducItem />
                  </SwiperSlide>
                  <SwiperSlide>
                    <ProducItem />
                  </SwiperSlide>
                </Swiper>
              </div>

              <div className="d-flex align-items-center mt-5">
                <div className="info w-75">
                  <h3 className="mb-0 hd">SẢN PHẨM MỚI</h3>
                  <p className="text-light text-sml mb-0">
                    Mua ngay để bắt kịp xu hướng.
                  </p>
                </div>
                <Button className="viewAllButton ml-auto ">
                  Xem tất cả <IoIosArrowRoundForward />
                </Button>
              </div>

              <div className="product_row productRow2 w-100 mt-4 d-flex">
                <ProducItem />
                <ProducItem />
                <ProducItem />
                <ProducItem />
                <ProducItem />
                <ProducItem />
                <ProducItem />
                <ProducItem />
              </div>

              <div className="d-flex mt-4 mb-5 bannerSec">
                <div className="banner ">
                  <img src={banner3} className="cursor w-100" alt="Banner" />
                </div>
                <div className="banner ">
                  <img src={banner4} className="cursor w-100" alt="Banner" />
                </div>
                <div className="banner ">
                  <img src={banner5} className="cursor w-100" alt="Banner" />
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>
    </>
  );
};

export default Home;
